{
  "name": "xi",
  "version": "0.1.0",
  "description": "Xi /ksi/ — The next-generation AI coding tool",
  "main": "./out/main/index.js",
  "author": {
    "name": "Elinx",
    "email": "xizzuli@163.com"
  },
  "scripts": {
    "dev": "electron-vite dev",
    "build": "electron-vite build",
    "preview": "electron-vite preview",
    "typecheck": "tsc --noEmit",
    "test": "vitest run",
    "package": "electron-vite build && electron-builder --publish never",
    "package:mac": "electron-vite build && electron-builder --mac --publish never",
    "package:win": "electron-vite build && electron-builder --win --publish never",
    "package:linux": "electron-vite build && electron-builder --linux --publish never",
    "release": "electron-vite build && electron-builder --publish always"
  },
  "dependencies": {
    "@earendil-works/pi-coding-agent": "^0.78.0",
    "@shikijs/transformers": "^4.1.0",
    "@tailwindcss/typography": "^0.5.19",
    "@xterm/addon-fit": "^0.11.0",
    "@xterm/xterm": "^6.0.0",
    "chokidar": "^5.0.0",
    "cmdk": "^1.1.1",
    "fabric": "^6.9.1",
    "node-pty": "^1.1.0",
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "react-markdown": "^10.1.0",
    "rehype-raw": "^7.0.0",
    "remark-gfm": "^4.0.1",
    "shiki": "^4.1.0",
    "simple-git": "^3.36.0",
    "zustand": "^5.0.14"
  },
  "devDependencies": {
    "@tailwindcss/vite": "^4.0.0",
    "@types/react": "^19.0.0",
    "@types/react-dom": "^19.0.0",
    "@vitejs/plugin-react": "^4.3.0",
    "electron": "^35.0.0",
    "electron-builder": "^26.0.0",
    "electron-vite": "^3.0.0",
    "playwright": "^1.60.0",
    "sharp": "^0.34.5",
    "tailwindcss": "^4.0.0",
    "typescript": "^5.7.0",
    "vitest": "^4.1.7"
  },
  "build": {
    "appId": "works.earendil.xi",
    "productName": "Xi",
    "directories": {
      "output": "dist"
    },
    "files": [
      "out/**/*"
    ],
    "artifactName": "Xi-${version}-${arch}-${os}.${ext}",
    "mac": {
      "artifactName": "Xi-${version}-${arch}-mac.${ext}",
      "target": [
        {
          "target": "dmg",
          "arch": [
            "x64",
            "arm64"
          ]
        },
        {
          "target": "zip",
          "arch": [
            "x64",
            "arm64"
          ]
        }
      ],
      "category": "public.app-category.developer-tools",
      "icon": "build/icon/icon.icns"
    },
    "win": {
      "artifactName": "Xi-${version}-${arch}-win.${ext}",
      "target": [
        {
          "target": "nsis",
          "arch": [
            "x64",
            "arm64"
          ]
        },
        {
          "target": "portable",
          "arch": [
            "x64"
          ]
        }
      ],
      "icon": "build/icon/icon.ico"
    },
    "linux": {
      "artifactName": "Xi-${version}-${arch}-linux.${ext}",
      "target": [
        {
          "target": "AppImage",
          "arch": [
            "x64"
          ]
        },
        {
          "target": "deb",
          "arch": [
            "x64"
          ]
        }
      ],
      "category": "Development",
      "icon": "build/icon"
    },
    "nsis": {
      "artifactName": "Xi-${version}-${arch}-win-setup.${ext}",
      "oneClick": false,
      "allowToChangeInstallationDirectory": true,
      "deleteAppDataOnUninstall": true
    }
  }
}
